#include <bits/stdc++.h>
using namespace std;
struct Node{
    int v,x;
}a[20004],c[20004];
int n;
bool cmp(Node a,Node b){
    return a.v<b.v;
}
int lowbit(int x){
    return x&(-x);
}
void Add(int x,int y){
    if(x>2e4)
        return;
    c[x].v+=y,c[x].x++;
    Add(x+lowbit(x),y);
}
Node Sum(int x){
    if(!x)
        return {0,0};
    return {c[x].v+Sum(x-lowbit(x)).v,c[x].x+Sum(x-lowbit(x)).x};
}
int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&a[i].v,&a[i].x);
    sort(a+1,a+n+1,cmp);
    long long cnt=0,ans=0;
    for(int i=1;i<=2e4;i++)
    	c[i]={0,0};
    for(int i=1;i<=n;i++){
        Node t=Sum(a[i].x);
        //cout<<a[i].v<<' '<<a[i].x<<' '<<t.v<<' '<<t.x<<'\n'; 
        ans+=1LL*a[i].v*(1LL*a[i].x*t.x-t.v);
        ans+=1LL*a[i].v*((cnt-t.v)-1LL*a[i].x*(i-t.x-1));
        Add(a[i].x,a[i].x),cnt+=a[i].x;
    }
    printf("%lld",ans);
    return 0;
}
